const defaultNow = () => {
  if (typeof performance !== 'undefined' && typeof performance.now === 'function') {
    return performance.now();
  }
  return Date.now();
};

export default async function runWithPerfBudget(fn, budgetMs, now = defaultNow) {
  if (typeof fn !== 'function') throw new TypeError('fn must be a function');
  if (!Number.isFinite(budgetMs) || budgetMs < 0) throw new TypeError('budgetMs must be a non-negative number');

  const start = now();
  const out = fn();
  const value = out && typeof out.then === 'function' ? await out : out;
  const end = now();

  const durationMs = Math.max(0, end - start);
  return { ok: durationMs <= budgetMs, durationMs, value };
}
